+    if let Ok(parsed) = trimmed.parse::<i64>() {
+        return parsed;
+    }
+    if let Ok(parsed) = trimmed.parse::<f64>() {
+        return format!("{:.0}", parsed.trunc()).parse::<i64>().unwrap_or(0);
+    }
+    mcp_agent_mail_db::migrate::text_to_micros(trimmed, "projects_screen", "created_at", 0)
+        .ok()
+        .flatten()
+        .unwrap_or(0)
+}
